css:
.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
  width: 50px;
  aspect-ratio: 1;
  border: 2px solid;
  --c: conic-gradient(from -90deg at calc(100% - 2px) calc(100% - 2px),#0000 0 90deg,currentColor 0);
  background: var(--c),var(--c);
  background-size: 16px 16px;
  background-position: 0 0;
  animation: l3 1s infinite;
}@keyframes l3{100% {background-position: -16px -16px,16px 16px}}
